    val n = nums.size
    var maxSum = Long.MIN_VALUE

    // Precompute prefix sums for quick range sum calculation
    val prefix = LongArray(n + 1)
    for (i in 0 until n) {
        prefix[i + 1] = prefix[i] + nums[i]
    }

    // Precompute left increasing segments
    val left = IntArray(n)
    for (i in 1 until n) {
        if (nums[i] > nums[i - 1]) {
            left[i] = left[i - 1] + 1
        } else {
            left[i] = 0
        }
    }

    // Precompute right increasing segments (from right to left)
    val right = IntArray(n)
    for (i in n - 2 downTo 0) {
        if (nums[i] < nums[i + 1]) {
            right[i] = right[i + 1] + 1
        } else {
            right[i] = 0
        }
    }

    // Iterate all possible p and q positions
    for (p in 1 until n - 2) {
        for (q in p + 1 until n - 1) {
            // Check if nums[p] > nums[q] (decreasing segment between p and q)
            if (nums[p] > nums[q]) {
                // Check left increasing segment (l to p)
                val l = p - left[p] - 1
                if (l >= 0 && left[p] >= 1) {
                    // Check right increasing segment (q to r)
                    val r = q + right[q] + 1
                    if (r < n && right[q] >= 1) {
                        // Calculate the sum from l to r
                        val currentSum = prefix[r + 1] - prefix[l]
                        if (currentSum > maxSum) {
